// Runtime configuration for Holodex Neo.
//
// In Docker, this file is generated automatically by the entrypoint script
// from environment variables (DISCORD_CLIENT_ID, GOOGLE_CLIENT_ID).
//
// For local development, use a .env.local file with VITE_* prefixed vars:
//   VITE_DISCORD_CLIENT_ID=your-id
//   VITE_GOOGLE_CLIENT_ID=your-id.apps.googleusercontent.com
//
// Uncomment and edit below to override at runtime without rebuilding:
// window.__HOLODEX_CONFIG__ = {
//   DISCORD_CLIENT_ID: "",
//   GOOGLE_CLIENT_ID: "",
// };
